        if (usedNames[fileName]) {
          usedNames[fileName]++;
          fileName = baseFileName + '_' + usedNames[fileName] + '.xlsx';
        } else {
          usedNames[fileName] = 1;
        }
        zip.file(fileName, arrayBuf);
